  font-weight: 600;
  color: #666;
}

.value {
  color: #111;
}

.notes {
  margin-bottom: 24px;
  padding-top: 16px;
  border-top: 2px solid #f0f0f0;
}

.notes h3 {
  font-size: 16px;
  margin-bottom: 8px;
  color: #666;
}

.notes p {
  line-height: 1.6;
  color: #111;
}

.actions {
