./src/views/RecordFormView.vue<pre><code>&lt;script setup&gt;
import { ref, computed, onMounted } from 'vue';
import { useRouter, useRoute } from 'vue-router';
import AppHeader from '@/components/layout/AppHeader.vue';
import AppInput from '@/components/forms/AppInput.vue';
import AppButton from '@/components/forms/AppButton.vue';
import { useRecords } from '@/composables/useRecords';

const router = useRouter();
const route = useRoute();
const { addRecord, getRecord, updateRecord } = useRecords();

const isEditMode = computed(() =&gt; route.params.id !== 'new');

const form = ref({
  title: '',
  duration: '',
  notes: '',
});

onMounted(() =&gt; {
  if (isEditMode.value) {
    const record = getRecord(route.params.id);
    if (record) {
      form.value = {
        title: record.title,
        duration: record.duration,
        notes: record.notes || '',
      };
    } else {
      router.push('/records');
    }
  }
});

function handleSubmit() {
  if (!form.value.title || !form.value.duration) {
    alert('Preencha os campos obrigatórios');
    return;
  }

  if (isEditMode.value) {
    updateRecord(route.params.id, form.value);
  } else {
    addRecord(form.value);
  }

  router.push('/records');
}
&lt;/script&gt;

&lt;template&gt;
  &lt;div&gt;
    &lt;AppHeader
      :title="isEditMode ? 'Editar Registro' : 'Novo Registro'"
      show-back
      @back="router.back()"
    /&gt;

    &lt;div class="page"&gt;
      &lt;form @submit.prevent="handleSubmit" class="form"&gt;
        &lt;AppInput
          v-model="form.title"
          label="Título"
          placeholder="Ex: Estudar Vue.js"
          required
        /&gt;

        &lt;AppInput
          v-model.number="form.duration"
          label="Duração (minutos)"
          type="number"
          placeholder="Ex: 60"
          required
        /&gt;

        &lt;div class="textarea-group"&gt;
          &lt;label class="label"&gt;Observações&lt;/label&gt;
          &lt;textarea
            v-model="form.notes"
            rows="4"
            class="textarea"
            placeholder="Adicione observações sobre a atividade..."
          &gt;&lt;/textarea&gt;
        &lt;/div&gt;

        &lt;AppButton type="submit"&gt;
          {{ isEditMode ? 'Salvar alterações' : 'Criar registro' }}
        &lt;/AppButton&gt;
      &lt;/form&gt;
    &lt;/div&gt;
  &lt;/div&gt;
&lt;/template&gt;

&lt;style scoped&gt;
.form {
  background: white;
  padding: 20px;
  border-radius: 12px;
}

.textarea-group {
  margin-bottom: 16px;
}

.label {
  display: block;
  margin-bottom: 6px;
  font-size: 14px;
  font-weight: 500;
  color: #333;
}

.textarea {
  width: 100%;
  padding: 12px 16px;
  font-size: 16px;
  border: 2px solid #ddd;
  border-radius: 8px;
  font-family: inherit;
  resize: vertical;
  transition: border-color 0.2s;
}

.textarea:focus {
  outline: none;
  border-color: #0b5cff;
}
&lt;/style&gt;
</code></pre>

